function formatToolResult(toolName, result) {
  if (!result) {
    return source_default.gray("(no result)");
  }
  if (typeof result === "string") {
    return result;
  }
  try {
    if (toolName.includes("memory_search") || toolName.includes("search_memory")) {
      return formatMemorySearchResult(result);
    }
    if (toolName.includes("search_graph") || toolName.includes("query_graph") || toolName.includes("get_neighbors")) {
      console.log("Knowledge graph result");
      return formatKnowledgeGraphResult(result);
    }
    if (toolName.includes("reasoning") || toolName.includes("extract_reasoning") || toolName.includes("evaluate_reasoning")) {
      return formatReasoningResult(result);
    }
    if (toolName.includes("extract_and_operate") || toolName.includes("memory_operation")) {
      return formatMemoryOperationResult(result);
    }
    if (toolName.includes("add_node") || toolName.includes("add_edge") || toolName.includes("update_node") || toolName.includes("delete_node")) {
      return formatKnowledgeGraphModificationResult(result);
    }
    if (toolName.includes("read_file") || toolName.includes("write_file") || toolName.includes("list_files")) {
      return formatMCPFileResult(toolName, result);
    }
    return formatGenericResult(result);
  } catch (error) {
    logger.debug("Error formatting tool result, falling back to JSON", { error, toolName });
    if (result && result.error) {
      return source_default.red(`\u274C Error: ${result.error}`);
    }
    return JSON.stringify(result, null, 2);
  }
}
function formatMemorySearchResult(result) {
  if (!result.success) {
    return source_default.red(`\u274C Search failed: ${result.error || "Unknown error"}`);
  }
  const output = [];
  output.push(source_default.blue.bold(`\u{1F50D} Memory Search Results`));
  output.push(source_default.gray(`Query: "${result.query}"`));
  output.push(
    source_default.gray(`Found ${result.results.length} result(s) in ${result.metadata.searchTime}ms`)
  );
  output.push("");
  if (result.results.length === 0) {
    output.push(source_default.yellow("No results found"));
  } else {
    result.results.forEach((item, index) => {
      output.push(
        source_default.cyan(
          `${index + 1}. ${source_default.bold(item.text.substring(0, 80))}${item.text.length > 80 ? "..." : ""}`
        )
      );
      output.push(source_default.gray(`   \u{1F4CA} Similarity: ${(item.similarity * 100).toFixed(1)}%`));
      if (item.confidence) {
        output.push(source_default.gray(`   \u{1F3AF} Confidence: ${(item.confidence * 100).toFixed(1)}%`));
      }
      if (item.domain) {
        output.push(source_default.gray(`   \u{1F3F7}\uFE0F  Domain: ${item.domain}`));
      }
      output.push(source_default.gray(`   \u{1F3F7}\uFE0F  Tags: ${item.tags.join(", ")}`));
      output.push(source_default.gray(`   \u{1F4C5} ${new Date(item.timestamp).toLocaleString()}`));
      output.push("");
    });
    output.push(source_default.gray(`\u{1F4CA} Summary:`));
    output.push(
      source_default.gray(`   \u2022 Max similarity: ${(result.metadata.maxSimilarity * 100).toFixed(1)}%`)
    );
    output.push(
      source_default.gray(`   \u2022 Min similarity: ${(result.metadata.minSimilarity * 100).toFixed(1)}%`)
    );
    output.push(
      source_default.gray(
        `   \u2022 Average similarity: ${(result.metadata.averageSimilarity * 100).toFixed(1)}%`
      )
    );
    if (result.metadata.usedFallback) {
      output.push(source_default.yellow(`   \u26A0\uFE0F  Used fallback search`));
    }
  }
  return output.join("\n");
}
function formatKnowledgeGraphResult(result) {
  if (!result.success) {
    console.log("Knowledge graph result", result.error);
    return source_default.red(`\u274C Graph query failed: ${result.error || "Unknown error"}`);
  }
  const output = [];
  output.push(source_default.blue.bold(`\u{1F578}\uFE0F  Knowledge Graph Results`));
  if (result.message) {
    output.push(source_default.gray(result.message));
  }
  if (result.executionTime) {
    output.push(source_default.gray(`Execution time: ${result.executionTime}ms`));
  }
  output.push("");
  if (result.nodes && result.nodes.length > 0) {
    output.push(source_default.cyan.bold(`\u{1F4CD} Nodes (${result.nodes.length}):`));
    result.nodes.slice(0, 10).forEach((node, index) => {
      output.push(
        source_default.cyan(
          `  ${index + 1}. ${source_default.bold(node.name)} ${node.type ? source_default.gray(`(${node.type})`) : ""}`
        )
      );
      if (node.score) {
        output.push(source_default.gray(`     \u{1F4CA} Score: ${(node.score * 100).toFixed(1)}%`));
      }
      if (node.matchReason) {
        output.push(source_default.gray(`     \u{1F3AF} Match: ${node.matchReason}`));
      }
      if (node.properties && Object.keys(node.properties).length > 0) {
        const propStr = Object.entries(node.properties).slice(0, 3).map(([k, v]) => `${k}: ${v}`).join(", ");
        output.push(source_default.gray(`     \u{1F3F7}\uFE0F  ${propStr}`));
      }
    });
    if (result.nodes.length > 10) {
      output.push(source_default.gray(`  ... and ${result.nodes.length - 10} more`));
    }
    output.push("");
  }
  if (result.edges && result.edges.length > 0) {
    output.push(source_default.magenta.bold(`\u{1F517} Relationships (${result.edges.length}):`));
    result.edges.slice(0, 10).forEach((edge, index) => {
      output.push(
        source_default.magenta(
          `  ${index + 1}. ${source_default.bold(edge.source)} ${source_default.gray("\u2192")} ${source_default.bold(edge.target)}`
        )
      );
      output.push(source_default.gray(`     \u{1F3F7}\uFE0F  Type: ${edge.type}`));
      if (edge.score) {
        output.push(source_default.gray(`     \u{1F4CA} Score: ${(edge.score * 100).toFixed(1)}%`));
      }
    });
    if (result.edges.length > 10) {
      output.push(source_default.gray(`  ... and ${result.edges.length - 10} more`));
    }
    output.push("");
  }
  if (result.related && result.related.length > 0) {
    output.push(source_default.yellow.bold(`\u{1F517} Related Entities (${result.related.length}):`));
    result.related.slice(0, 5).forEach((rel, index) => {
      output.push(
        source_default.yellow(
          `  ${index + 1}. ${source_default.bold(rel.entity.name)} ${source_default.gray(`(distance: ${rel.distance})`)}`
        )
      );
      output.push(source_default.gray(`     \u{1F517} via ${rel.relationship.type}`));
    });
    if (result.related.length > 5) {
      output.push(source_default.gray(`  ... and ${result.related.length - 5} more`));
    }
    output.push("");
  }
  if (result.totalCount) {
    output.push(source_default.gray(`\u{1F4CA} Total results: ${result.totalCount}`));
  }
  return output.join("\n");
}
function formatReasoningResult(result) {
  if (!result.success) {
    return source_default.red(`\u274C Reasoning analysis failed: ${result.error || "Unknown error"}`);
  }
  const output = [];
  output.push(source_default.blue.bold(`\u{1F9E0} Reasoning Analysis`));
  output.push("");
  if (result.steps && result.steps.length > 0) {
    output.push(source_default.cyan.bold(`\u{1F4AD} Reasoning Steps (${result.steps.length}):`));
    result.steps.forEach((step, index) => {
      const typeIcon = getStepTypeIcon(step.type);
      output.push(source_default.cyan(`  ${index + 1}. ${typeIcon} ${source_default.bold(step.type)}`));
      output.push(
        source_default.gray(
          `     ${step.content.substring(0, 100)}${step.content.length > 100 ? "..." : ""}`
        )
      );
    });
    output.push("");
  }
  if (result.evaluation) {
    output.push(source_default.yellow.bold(`\u{1F4CA} Quality Evaluation:`));
    output.push(
      source_default.yellow(`  Quality Score: ${(result.evaluation.qualityScore * 100).toFixed(1)}%`)
    );
    if (result.evaluation.issues && result.evaluation.issues.length > 0) {
      output.push(source_default.red(`  Issues Found (${result.evaluation.issues.length}):`));
      result.evaluation.issues.forEach((issue, index) => {
        const severityColor = issue.severity === "high" ? source_default.red : issue.severity === "medium" ? source_default.yellow : source_default.gray;
        output.push(severityColor(`    ${index + 1}. ${issue.description}`));
      });
    }
    if (result.evaluation.suggestions && result.evaluation.suggestions.length > 0) {
      output.push(source_default.green(`  Suggestions (${result.evaluation.suggestions.length}):`));
      result.evaluation.suggestions.forEach((suggestion, index) => {
        output.push(source_default.green(`    ${index + 1}. ${suggestion}`));
      });
    }
    output.push("");
  }
  if (result.patterns && result.patterns.length > 0) {
    output.push(source_default.magenta.bold(`\u{1F50D} Similar Patterns (${result.patterns.length}):`));
    result.patterns.slice(0, 3).forEach((pattern, index) => {
      output.push(
        source_default.magenta(
          `  ${index + 1}. ${source_default.bold(pattern.context)} ${source_default.gray(`(${(pattern.similarity * 100).toFixed(1)}% match)`)}`
        )
      );
      output.push(source_default.gray(`     ${pattern.steps.length} steps`));
    });
    if (result.patterns.length > 3) {
      output.push(source_default.gray(`  ... and ${result.patterns.length - 3} more`));
    }
    output.push("");
  }
  return output.join("\n");
}
function formatMemoryOperationResult(result) {
  if (!result.success) {
    return source_default.red(`\u274C Memory operation failed: ${result.error || "Unknown error"}`);
  }
  const output = [];
  output.push(source_default.blue.bold(`\u{1F4BE} Memory Operation Results`));
  output.push("");
  if (result.operations) {
    const ops = result.operations;
    const summary = [];
    if (ops.added > 0) summary.push(source_default.green(`${ops.added} added`));
    if (ops.updated > 0) summary.push(source_default.yellow(`${ops.updated} updated`));
    if (ops.deleted > 0) summary.push(source_default.red(`${ops.deleted} deleted`));
    if (ops.unchanged > 0) summary.push(source_default.gray(`${ops.unchanged} unchanged`));
    if (summary.length > 0) {
      output.push(source_default.cyan(`\u{1F4CA} Summary: ${summary.join(", ")}`));
      output.push("");
    }
  }
  if (result.memories && result.memories.length > 0) {
    output.push(source_default.cyan.bold(`\u{1F4DD} Memory Entries (${result.memories.length}):`));
    result.memories.slice(0, 5).forEach((memory, index) => {
      const eventIcon = getMemoryEventIcon(memory.event);
      output.push(
        source_default.cyan(
          `  ${index + 1}. ${eventIcon} ${source_default.bold(memory.event)} - ${memory.text.substring(0, 60)}${memory.text.length > 60 ? "..." : ""}`
        )
      );
      if (memory.confidence) {
        output.push(source_default.gray(`     \u{1F3AF} Confidence: ${(memory.confidence * 100).toFixed(1)}%`));
      }
      if (memory.tags && memory.tags.length > 0) {
        output.push(source_default.gray(`     \u{1F3F7}\uFE0F  Tags: ${memory.tags.join(", ")}`));
      }
      if (memory.reasoning) {
        output.push(
          source_default.gray(
            `     \u{1F4AD} Reasoning: ${memory.reasoning.substring(0, 80)}${memory.reasoning.length > 80 ? "..." : ""}`
          )
        );
      }
    });
    if (result.memories.length > 5) {
      output.push(source_default.gray(`  ... and ${result.memories.length - 5} more`));
    }
    output.push("");
  }
  return output.join("\n");
}
function formatKnowledgeGraphModificationResult(result) {
  if (!result.success) {
    return source_default.red(`\u274C Graph modification failed: ${result.error || "Unknown error"}`);
  }
  const output = [];
  output.push(source_default.blue.bold(`\u{1F578}\uFE0F  Knowledge Graph Updated`));
  if (result.message) {
    output.push(source_default.gray(result.message));
  }
  output.push("");
  if (result.node) {
    output.push(
      source_default.green(
        `\u2705 Node: ${source_default.bold(result.node.name)} ${result.node.type ? source_default.gray(`(${result.node.type})`) : ""}`
      )
    );
    if (result.node.properties && Object.keys(result.node.properties).length > 0) {
      const propStr = Object.entries(result.node.properties).slice(0, 3).map(([k, v]) => `${k}: ${v}`).join(", ");
      output.push(source_default.gray(`   \u{1F3F7}\uFE0F  Properties: ${propStr}`));
    }
  }
  if (result.edge) {
    output.push(
      source_default.green(
        `\u2705 Relationship: ${source_default.bold(result.edge.source)} ${source_default.gray("\u2192")} ${source_default.bold(result.edge.target)}`
      )
    );
    output.push(source_default.gray(`   \u{1F3F7}\uFE0F  Type: ${result.edge.type}`));
    if (result.edge.properties && Object.keys(result.edge.properties).length > 0) {
      const propStr = Object.entries(result.edge.properties).slice(0, 3).map(([k, v]) => `${k}: ${v}`).join(", ");
      output.push(source_default.gray(`   \u{1F3F7}\uFE0F  Properties: ${propStr}`));
    }
  }
  if (result.statistics) {
    output.push("");
    output.push(source_default.gray(`\u{1F4CA} Graph Statistics:`));
    if (result.statistics.totalNodes) {
      output.push(source_default.gray(`   \u2022 Total nodes: ${result.statistics.totalNodes}`));
    }
    if (result.statistics.totalEdges) {
      output.push(source_default.gray(`   \u2022 Total edges: ${result.statistics.totalEdges}`));
    }
  }
  return output.join("\n");
}
function formatMCPFileResult(toolName, result) {
  if (result.error) {
    return source_default.red(`\u274C ${toolName} failed: ${result.error}`);
  }
  if (result.content) {
    const output = [];
    output.push(source_default.green(`\u2705 ${toolName} completed successfully`));
    if (toolName.includes("read_file") && Array.isArray(result.content)) {
      const textContent = result.content.find((item) => item.type === "text");
      if (textContent && textContent.text) {
        const lines = textContent.text.split("\n").length;
        const chars = textContent.text.length;
        output.push(source_default.gray(`\u{1F4C4} File read: ${lines} lines, ${chars} characters`));
      }
    } else if (toolName.includes("list_files") && Array.isArray(result.content)) {
      const files = result.content.filter((item) => item.type === "file").length;
      const dirs = result.content.filter((item) => item.type === "directory").length;
      output.push(source_default.gray(`\u{1F4C1} Listed: ${files} files, ${dirs} directories`));
    }
    return output.join("\n");
  }
  return source_default.green(`\u2705 ${toolName} completed successfully`);
}
function formatGenericResult(result) {
  if (result.success === false || result.error) {
    return source_default.red(`\u274C ${result.error || result.message || "Operation failed"}`);
  }
  const hasData = result.data || result.content && !result.error;
  const isExplicitSuccess = result.success === true;
  if (isExplicitSuccess || hasData) {
    const output = [];
    output.push(source_default.green(`\u2705 ${result.message || "Operation completed successfully"}`));
    if (result.data) {
      if (typeof result.data === "object" && result.data !== null) {
        const keys = Object.keys(result.data);
        if (keys.length > 0) {
          output.push("");
          output.push(source_default.gray("\u{1F4C4} Data:"));
          keys.slice(0, 5).forEach((key) => {
            const value = result.data[key];
            const displayValue = typeof value === "string" ? value : JSON.stringify(value);
            output.push(
              source_default.gray(
                `   \u2022 ${key}: ${displayValue.substring(0, 50)}${displayValue.length > 50 ? "..." : ""}`
              )
            );
          });
          if (keys.length > 5) {
            output.push(source_default.gray(`   ... and ${keys.length - 5} more fields`));
          }
        }
      }
    }
    return output.join("\n");
  }
  return source_default.green(`\u2705 ${result.message || "Operation completed successfully"}`);
}
function getStepTypeIcon(type) {
  switch (type.toLowerCase()) {
    case "thought":
      return "\u{1F4AD}";
    case "action":
      return "\u26A1";
    case "observation":
      return "\u{1F441}\uFE0F";
    case "decision":
      return "\u{1F3AF}";
    case "conclusion":
      return "\u{1F393}";
    case "reflection":
      return "\u{1FA9E}";
    default:
      return "\u2022";
  }
}
function getMemoryEventIcon(event) {
  switch (event.toUpperCase()) {
    case "ADD":
      return "\u2795";
    case "UPDATE":
      return "\u270F\uFE0F";
    case "DELETE":
      return "\u{1F5D1}\uFE0F";
    case "NONE":
      return "\u26AA";
    default:
      return "\u2022";
  }
}

// src/core/brain/llm/services/openrouter.ts
import { v4 as uuidv4 } from "uuid";
var OpenRouterService = class {
  client;
  model;
  mcpManager;
  unifiedToolManager;
  contextManager;
  maxIterations;
  eventManager;
  constructor(client, model, mcpManager, contextManager, maxIterations = 5, unifiedToolManager) {
    this.client = client;
    this.model = model;
    this.mcpManager = mcpManager;
    this.unifiedToolManager = unifiedToolManager;
    this.contextManager = contextManager;
    this.maxIterations = maxIterations;
  }
  setEventManager(eventManager) {
    this.eventManager = eventManager;
  }
  async generate(userInput, imageData) {
    await this.contextManager.addUserMessage(userInput, imageData);
    const messageId = uuidv4();
    const startTime = Date.now();
    const sessionId = this.contextManager?.sessionId;
    if (this.eventManager && sessionId) {
      this.eventManager.emitSessionEvent(sessionId, SessionEvents.LLM_RESPONSE_STARTED, {
        sessionId,
        messageId,
        model: this.model,
        timestamp: startTime
      });
    }
    let formattedTools;
    if (this.unifiedToolManager) {
      formattedTools = await this.unifiedToolManager.getToolsForProvider("openrouter");
    } else {
      const rawTools = await this.mcpManager.getAllTools();
      formattedTools = this.formatToolsForOpenRouter(rawTools);
    }
    logger.silly(`Formatted tools for OpenRouter: ${JSON.stringify(formattedTools, null, 2)}`);
    let iterationCount = 0;
    try {
      while (iterationCount < this.maxIterations) {
        iterationCount++;
        const { message } = await this.getAIResponseWithRetries(formattedTools, userInput);
        if (!message.tool_calls || message.tool_calls.length === 0) {
          const responseText = message.content || "";
          await this.contextManager.addAssistantMessage(responseText);
          if (this.eventManager && sessionId) {
            this.eventManager.emitSessionEvent(sessionId, SessionEvents.LLM_RESPONSE_COMPLETED, {
              sessionId,
              messageId,
              model: this.model,
              duration: Date.now() - startTime,
              timestamp: Date.now(),
              response: responseText
            });
          }
          return responseText;
        }
        if (message.content && message.content.trim()) {
          logger.info(`\u{1F4AD} ${message.content.trim()}`);
          if (this.eventManager && sessionId) {
            this.eventManager.emitSessionEvent(sessionId, SessionEvents.LLM_THINKING, {
              sessionId,
              messageId,
              timestamp: Date.now()
            });
          }
        }
        await this.contextManager.addAssistantMessage(message.content, message.tool_calls);
        for (const toolCall of message.tool_calls) {
          logger.debug(`OpenRouter tool call initiated: ${JSON.stringify(toolCall, null, 2)}`);
          logger.info(`\u{1F527} Using tool: ${toolCall.function.name}`);
          const toolName = toolCall.function.name;
          let args = {};
          try {
            args = JSON.parse(toolCall.function.arguments);
          } catch (e) {
            logger.error(`Error parsing arguments for ${toolName}:`, e);
            await this.contextManager.addToolResult(toolCall.id, toolName, {
              error: `Failed to parse arguments: ${e}`
            });
            continue;
          }
          try {
            let result;
            if (this.unifiedToolManager) {
              result = await this.unifiedToolManager.executeTool(toolName, args, sessionId);
            } else {
              result = await this.mcpManager.executeTool(toolName, args);
            }
            const formattedResult = formatToolResult(toolName, result);
            logger.info(`\u{1F4CB} Tool Result:
${formattedResult}`);
            await this.contextManager.addToolResult(toolCall.id, toolName, result);
          } catch (error) {
            const errorMessage = error instanceof Error ? error.message : String(error);
            logger.error(`Tool execution error for ${toolName}: ${errorMessage}`);
            await this.contextManager.addToolResult(toolCall.id, toolName, {
              error: errorMessage
            });
          }
        }
      }
      logger.warn(`Reached maximum iterations (${this.maxIterations}) for task.`);
      const finalResponse = "Task completed but reached maximum tool call iterations.";
      await this.contextManager.addAssistantMessage(finalResponse);
      return finalResponse;
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      logger.error(`Error in OpenRouter service API call: ${errorMessage}`, { error });
      await this.contextManager.addAssistantMessage(`Error processing request: ${errorMessage}`);
      return `Error processing request: ${errorMessage}`;
    }
  }
  /**
   * Direct generate method that bypasses conversation context
   * Used for internal tool operations that shouldn't pollute conversation history
   * @param userInput - The input to generate a response for
   * @param systemPrompt - Optional system prompt to use
   * @returns Promise<string> - The generated response
   */
  async directGenerate(userInput, systemPrompt) {
    try {
      logger.debug("OpenRouterService: Direct generate call (bypassing conversation context)", {
        inputLength: userInput.length,
        hasSystemPrompt: !!systemPrompt
      });
      const messages = [];
      if (systemPrompt) {
        messages.push({
          role: "system",
          content: systemPrompt
        });
      }
      messages.push({
        role: "user",
        content: userInput
      });
      const response = await this.client.chat.completions.create({
        model: this.model,
        messages
        // No tools for direct calls - this is for simple text generation
      });
      const responseText = response.choices[0]?.message?.content || "";
      logger.debug("OpenRouterService: Direct generate completed", {
        responseLength: responseText.length
      });
      return responseText;
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      logger.error("OpenRouterService: Direct generate failed", {
        error: errorMessage,
        inputLength: userInput.length
      });
      throw new Error(`Direct generate failed: ${errorMessage}`);
    }
  }
  async getAllTools() {
    if (this.unifiedToolManager) {
      return await this.unifiedToolManager.getAllTools();
    }
    return this.mcpManager.getAllTools();
  }
  getConfig() {
    return {
      provider: "openrouter",
      model: this.model
    };
  }
  // Helper methods
  async getAIResponseWithRetries(tools, userInput) {
    let attempts = 0;
    const MAX_ATTEMPTS = 3;
    logger.debug(`Tools in OpenRouter response: ${tools.length}`);
    while (attempts < MAX_ATTEMPTS) {
      attempts++;
      try {
        const formattedMessages = await this.contextManager.getFormattedMessage({
          role: "user",
          content: userInput
        });
        const response = await this.client.chat.completions.create({
          model: this.model,
          messages: formattedMessages,
          tools: attempts === 1 ? tools : [],
          // Only offer tools on first attempt
          tool_choice: attempts === 1 ? "auto" : "none"
          // Disable tool choice on retry
        });
        logger.silly("OPENROUTER CHAT COMPLETION RESPONSE: ", JSON.stringify(response, null, 2));
        const message = response.choices[0]?.message;
        if (!message) {
          throw new Error("Received empty message from OpenRouter API");
        }
        return { message };
      } catch (error) {
        const apiError = error;
        logger.error(
          `Error in OpenRouter API call (Attempt ${attempts}/${MAX_ATTEMPTS}): ${apiError.message || JSON.stringify(apiError, null, 2)}`,
          { status: apiError.status, headers: apiError.headers }
        );
        if (apiError.status === 400 && apiError.error?.code === "context_length_exceeded") {
          logger.warn(
            `Context length exceeded. ContextManager compression might not be sufficient. Error details: ${JSON.stringify(apiError.error)}`
          );
        }
        if (attempts >= MAX_ATTEMPTS) {
          logger.error(`Failed to get response from OpenRouter after ${MAX_ATTEMPTS} attempts.`);
          throw error;
        }
        await new Promise((resolve2) => setTimeout(resolve2, 500 * attempts));
      }
    }
    throw new Error("Failed to get response after maximum retry attempts");
  }
  formatToolsForOpenRouter(tools) {
    return Object.entries(tools).map(([name, tool]) => {
      return {
        type: "function",
        function: {
          name,
          description: tool.description,
          parameters: tool.parameters
        }
      };
    });
  }
};

