    if (this.eventManager && sessionId) {
      this.eventManager.emitSessionEvent(sessionId, SessionEvents.LLM_RESPONSE_STARTED, {
        sessionId,
        messageId,
        model: this.model,
        timestamp: startTime
      });
    }
