var AwsConfigSchema = external_exports.object({
  region: external_exports.string().optional().describe("AWS region (defaults to us-east-1 or AWS_DEFAULT_REGION)"),
  accessKeyId: external_exports.string().optional().describe("AWS Access Key ID (can use AWS_ACCESS_KEY_ID env var)"),
  secretAccessKey: external_exports.string().optional().describe("AWS Secret Access Key (can use AWS_SECRET_ACCESS_KEY env var)"),
  sessionToken: external_exports.string().optional().describe("AWS Session Token (can use AWS_SESSION_TOKEN env var)"),
  inferenceProfileArn: external_exports.string().optional().describe(
    "ARN of the AWS Bedrock provisioned throughput (inference profile) for the selected model"
  )
});
var AzureConfigSchema = external_exports.object({
  endpoint: external_exports.string().url().describe("Azure OpenAI endpoint URL (required for Azure)"),
  deploymentName: external_exports.string().optional().describe("Azure deployment name (defaults to model name if not provided)")
});
var LLMConfigSchema = external_exports.object({
  provider: external_exports.string().nonempty().describe(
    "The LLM provider (e.g., 'openai', 'anthropic', 'openrouter', 'ollama', 'lmstudio', 'qwen', 'aws', 'azure', 'gemini')"
  ),
  model: external_exports.string().nonempty().describe("The specific model name for the selected provider"),
  apiKey: external_exports.string().optional().describe(
    "API key for the LLM provider (can also be set via environment variables using $VAR syntax). Not required for Ollama, LM Studio, or AWS (if using IAM roles)."
  ),
  maxIterations: external_exports.number().int().positive().optional().default(50).describe(
    "Maximum number of iterations for agentic loops or chained LLM calls, defaults to 50"
  ),
  baseURL: external_exports.string().url().optional().describe(
    "Base URL for the LLM provider (e.g., https://api.openai.com/v1, https://openrouter.ai/api/v1, http://localhost:1234/v1). \nSupported for OpenAI, OpenRouter, Ollama, LM Studio, and Qwen providers."
  ),
  qwenOptions: external_exports.object({
    enableThinking: external_exports.boolean().optional(),
    thinkingBudget: external_exports.number().int().positive().optional(),
    temperature: external_exports.number().min(0).max(2).optional(),
    top_p: external_exports.number().min(0).max(1).optional()
  }).optional().describe("Qwen-specific options for advanced configuration"),
  aws: AwsConfigSchema.optional().describe("AWS-specific configuration options"),
  azure: AzureConfigSchema.optional().describe("Azure-specific configuration options")
}).strict().superRefine((data, ctx) => {
  const providerLower = data.provider?.toLowerCase();
  const supportedProvidersList = [
    "openai",
    "anthropic",
    "openrouter",
    "ollama",
    "lmstudio",
    // Added LM Studio as a supported provider
    "qwen",
    "aws",
    "azure",
    "gemini"
  ];
  if (!supportedProvidersList.includes(providerLower)) {
    ctx.addIssue({
      code: external_exports.ZodIssueCode.custom,
      path: ["provider"],
      message: `Provider '${data.provider}' is not supported. Supported: ${supportedProvidersList.join(", ")}`
    });
  }
  if (providerLower === "aws") {
    if (!data.aws) {
      ctx.addIssue({
        code: external_exports.ZodIssueCode.custom,
        path: ["aws"],
        message: "AWS configuration object is required when using AWS provider"
      });
    }
  } else if (providerLower === "azure") {
    if (!data.azure) {
      ctx.addIssue({
        code: external_exports.ZodIssueCode.custom,
        path: ["azure"],
        message: "Azure configuration object is required when using Azure provider"
      });
    } else if (!data.azure.endpoint) {
      ctx.addIssue({
        code: external_exports.ZodIssueCode.custom,
        path: ["azure", "endpoint"],
        message: "Azure endpoint is required when using Azure provider"
      });
    }
    if (!data.apiKey || data.apiKey.trim().length === 0) {
      ctx.addIssue({
        code: external_exports.ZodIssueCode.custom,
        path: ["apiKey"],
        message: "API key is required for Azure OpenAI provider"
      });
    }
  } else if (providerLower !== "ollama" && providerLower !== "aws" && providerLower !== "lmstudio") {
    if (!data.apiKey || data.apiKey.trim().length === 0) {
      ctx.addIssue({
        code: external_exports.ZodIssueCode.custom,
        path: ["apiKey"],
        message: `API key is required for provider '${data.provider}'. Only Ollama, LM Studio, and AWS (with IAM roles) don't require an API key.`
      });
    }
  }
});

