init_esm_shims();
init_env();
async function getAllToolDefinitions(options = {}) {
  try {
    const memoryTools = await import("./memory-4X7NKRCG.js").then((m) => m.getMemoryTools(options));
    const systemTools = await import("./system-TCBBIJ5Z.js").then((m) => m.getSystemTools());
    let knowledgeGraphTools = {};
    if (env.KNOWLEDGE_GRAPH_ENABLED) {
      logger.debug("Knowledge graph enabled, loading knowledge graph tools");
      knowledgeGraphTools = await import("./knowledge_graph-XI3JIDTV.js").then(
        (m) => m.getKnowledgeGraphTools()
      );
    } else {
      logger.debug("Knowledge graph disabled, skipping knowledge graph tools");
    }
    const allTools = {
      ...memoryTools,
      ...systemTools,
      ...knowledgeGraphTools
    };
    return allTools;
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error("Failed to load tool definitions", { error: errorMessage });
    throw new Error(`Failed to load tool definitions: ${errorMessage}`);
  }
}
async function registerAllTools(toolManager, options = {}) {
  try {
    const tools = await getAllToolDefinitions(options);
    const registered = [];
    const failed = [];
    for (const [toolName, tool] of Object.entries(tools)) {
      try {
        const result2 = toolManager.registerTool(tool);
        if (result2.success) {
          registered.push(toolName);
        } else {
          failed.push({ name: toolName, error: result2.message });
          logger.warn(`Failed to register tool ${toolName}: ${result2.message}`);
        }
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        failed.push({ name: toolName, error: errorMessage });
        logger.error(`Error registering tool ${toolName}: ${errorMessage}`);
      }
    }
    const result = {
      registered,
      failed,
      total: Object.keys(tools).length
    };
    if (result.failed.length > 0) {
      logger.debug("Tool registration completed", {
        totalTools: result.total,
        successfullyRegistered: result.registered.length,
        failed: result.failed.length,
        embeddingEnabled: options.embeddingEnabled
      });
    }
    return result;
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error("Failed to register tools", { error: errorMessage });
    throw new Error(`Failed to register tools: ${errorMessage}`);
  }
}

